class TokenInfo:
    """Represents validated token information."""

    def __init__(self, token_row, client_row):
        self.token_id = token_row['id']
        self.client_id = token_row['client_id']
        self.user_id = token_row['user_id']
        self.scopes = set(token_row['scopes'].split() if token_row['scopes'] else [])
        self.expires_at = datetime.fromisoformat(token_row['expires_at'])
        self.token_type = token_row['token_type']
        self.client_name = client_row['client_name']
        self.client_scopes = set(client_row['scopes'].split() if client_row['scopes'] else [])

    def has_scope(self, scope):
        """Check if token has a specific scope."""
        return scope in self.scopes

    def has_any_scope(self, scopes):
        """Check if token has any of the specified scopes."""
        return bool(self.scopes.intersection(scopes))

    def has_all_scopes(self, scopes):
        """Check if token has all specified scopes."""
        return set(scopes).issubset(self.scopes)

    @property
    def is_expired(self):
        return datetime.utcnow() > self.expires_at

    def to_dict(self):
        return {
            'client_id': self.client_id,
            'user_id': self.user_id,
            'scopes': list(self.scopes),
            'expires_at': self.expires_at.isoformat(),
            'client_name': self.client_name
        }


def validate_access_token(access_token):
    """
    Validate an access token by checking the database.
    Returns TokenInfo if valid, None otherwise.
    """
    db = get_db()
    token_hash = hash_token(access_token)

    token_row = db.execute(
        '''SELECT t.*, c.client_name, c.scopes as client_scopes, c.is_active as client_active
           FROM oauth_tokens t
           JOIN oauth_clients c ON t.client_id = c.client_id
           WHERE t.access_token_hash = ?''',
        (token_hash,)
    ).fetchone()

    if token_row is None:
        return None, 'invalid_token', 'The access token is invalid.'

    if token_row['revoked']:
        return None, 'invalid_token', 'The access token has been revoked.'

    if not token_row['client_active']:
        return None, 'invalid_token', 'The client associated with this token has been deactivated.'

    expires_at = datetime.fromisoformat(token_row['expires_at'])
    if datetime.utcnow() > expires_at:
        return None, 'invalid_token', 'The access token has expired.'

    client_row = db.execute(
        'SELECT * FROM oauth_clients WHERE client_id = ?',
        (token_row['client_id'],)
    ).fetchone()

    token_info = TokenInfo(token_row, client_row)
    return token_info, None, None


def extract_token_from_request():
    """Extract the bearer token from the Authorization header or query parameters."""
    auth_header = request.headers.get('Authorization', '')

    if auth_header.startswith('Bearer '):
        return auth_header[7:].strip()

    # Fallback to query parameter (less secure, for specific use cases)
    token = request.args.get('access_token')
    if token:
        return token.strip()

    return None


