def require_oauth(*required_scopes, require_all=True):
    """
    Decorator to protect API endpoints with OAuth 2.0 token validation.
    
    Args:
        *required_scopes: Scopes required to access the endpoint.
        require_all: If True, all scopes are required. If False, any one scope suffices.
    
    Usage:
        @require_oauth('read', 'write')  # requires both scopes
        @require_oauth('read', 'write', require_all=False)  # requires any one scope
        @require_oauth()  # just requires a valid token, no specific scope
    """
    def decorator(f):
        @functools.wraps(f)
        def decorated_function(*args, **kwargs):
            # Extract token
            access_token = extract_token_from_request()
            if not access_token:
                log_audit_event('token_validation', status='failure', message='No token provided')
                return jsonify({
                    'error': 'invalid_request',
                    'error_description': 'Missing access token. Provide it via Authorization header (Bearer token).'
                }), 401

            # Validate token
            token_info, error, error_description = validate_access_token(access_token)

            if token_info is None:
                log_audit_event('token_validation', status='failure', message=error_description)
                response = jsonify({
                    'error': error,
                    'error_description': error_description
                })
                response.headers['WWW-Authenticate'] = f'Bearer error="{error}", error_description="{error_description}"'
                return response, 401

            # Check scopes
            if required_scopes:
                if require_all:
                    if not token_info.has_all_scopes(required_scopes):
                        missing = set(required_scopes) - token_info.scopes
                        log_audit_event(
                            'scope_check',
                            client_id=token_info.client_id,
                            token_id=token_info.token_id,
                            status='failure',
                            message=f'Missing scopes: {missing}'
                        )
                        return jsonify({
                            'error': 'insufficient_scope',
                            'error_description': f'Required scopes: {", ".join(required_scopes)}. Missing: {", ".join(missing)}.'
                        }), 403
                else:
                    if not token_info.has_any_scope(required_scopes):
                        log_audit_event(
                            'scope_check',
                            client_id=token_info.client_id,
                            token_id=token_info.token_id,
                            status='failure',
                            message=f'None of required scopes present: {required_scopes}'
                        )
                        return jsonify({
                            'error': 'insufficient_scope',
                            'error_description': f'At least one of these scopes is required: {", ".join(required_scopes)}.'
                        }), 403

            # Attach token info to request context
            g.token_info = token_info
            g.current_client_id = token_info.client_id
            g.current_user_id = token_info.user_id

            log_audit_event(
                'api_access',
                client_id=token_info.client_id,
                token_id=token_info.token_id,
                status='success'
            )

            return f(*args, **kwargs)

        return decorated_function
    return decorator


