@app.route('/oauth/token', methods=['POST'])
def issue_token():
    """
    OAuth 2.0 Token endpoint.
    Supports client_credentials and refresh_token grant types.
    """
    grant_type = request.form.get('grant_type')

    if grant_type == 'client_credentials':
        return _handle_client_credentials()
    elif grant_type == 'refresh_token':
        return _handle_refresh_token()
    else:
        return jsonify({
            'error': 'unsupported_grant_type',
            'error_description': 'Supported grant types: client_credentials, refresh_token'
        }), 400


def _authenticate_client():
    """Authenticate client using Basic auth or form parameters."""
    # Try Basic authentication first
    auth = request.authorization
    if auth:
        client_id = auth.username
        client_secret = auth.password
    else:
        client_id = request.form.get('client_id')
        client_secret = request.form.get('client_secret')

    if not client_id or not client_secret:
        return None, 'Client authentication required.'

    db = get_db()
    client = db.execute(
        'SELECT * FROM oauth_clients WHERE client_id = ? AND is_active = 1',
        (client_id,)
    ).fetchone()

    if client is None:
        return None, 'Invalid client credentials.'

    if hash_token(client_secret) != client['client_secret_hash']:
        return None, 'Invalid client credentials.'

    return client, None


def _handle_client_credentials():
    """Handle client_credentials grant type."""
    client, error = _authenticate_client()
    if client is None:
        log_audit_event('token_issue', status='failure', message=error)
        return jsonify({
            'error': 'invalid_client',
            'error_description': error
        }), 401

    if 'client_credentials' not in client['grant_types']:
        return jsonify({
            'error': 'unauthorized_client',
            'error_description': 'This client is not authorized for client_credentials grant.'
        }), 400

    # Check requested scopes
    requested_scopes = request.form.get('scope', client['scopes'])
    requested_scope_set = set(requested_scopes.split()) if requested_scopes else set()
    allowed_scope_set = set(client['scopes'].split()) if client['scopes'] else set()

    if requested_scope_set and not requested_scope_set.issubset(allowed_scope_set):
        invalid_scopes = requested_scope_set - allowed_scope_set
        return jsonify({
            'error': 'invalid_scope',
            'error_description': f'Invalid scopes: {", ".join(invalid_scopes)}'
        }), 400

    granted_scopes = ' '.join(requested_scope_set) if requested_scope_set else client['scopes']

    # Generate tokens
    access_token = generate_token()
    refresh_token = generate_token()
    expires_in = 3600  # 1 hour
    expires_at = datetime.utcnow() + timedelta(seconds=expires_in)
    refresh_expires_at = datetime.utcnow() + timedelta(days=30)

    db = get_db()

    # Store access token
    cursor = db.execute(
        '''INSERT INTO oauth_tokens (access_token_hash, token_type, client_id, scopes, expires_at)
           VALUES (?, 'Bearer', ?, ?, ?)''',
        (hash_token(access_token), client['client_id'], granted_scopes, expires_at.isoformat())
    )
    token_id = cursor.lastrowid

    # Store refresh token
    db.execute(
        '''INSERT INTO oauth_refresh_tokens (refresh_token_hash, access_token_id, client_id, expires_at)
           VALUES (?, ?, ?, ?)''',
        (hash_token(refresh_token), token_id, client['client_id'], refresh_expires_at.isoformat())
    )

    db.commit()

    log_audit_event(
        'token_issue',
        client_id=client['client_id'],
        token_id=token_id,
        status='success',
        message=f'Scopes: {granted_scopes}'
    )

    return jsonify({
        'access_token': access_token,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'refresh_token': refresh_token,
        'scope': granted_scopes
    }), 200


def _handle_refresh_token():
    """Handle refresh_token grant type."""
    client, error = _authenticate_client()
    if client is None:
        return jsonify({
            'error': 'invalid_client',
            'error_description': error
        }), 401

    refresh_token_value = request.form.get('refresh_token')
    if not refresh_token_value:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'refresh_token parameter is required.'
        }), 400

    db = get_db()
    refresh_token_hash = hash_token(refresh_token_value)

    refresh_row = db.execute(
        '''SELECT * FROM oauth_refresh_tokens 
           WHERE refresh_token_hash = ? AND client_id = ? AND revoked = 0''',
        (refresh_token_hash, client['client_id'])
    ).fetchone()

    if refresh_row is None:
        return jsonify({
            'error': 'invalid_grant',
            'error_description': 'Invalid or expired refresh token.'
        }), 400

    refresh_expires = datetime.fromisoformat(refresh_row['expires_at'])
    if datetime.utcnow() > refresh_expires:
        return jsonify({
            'error': 'invalid_grant',
            'error_description': 'Refresh token has expired.'
        }), 400

    # Revoke old tokens
    db.execute(
        'UPDATE oauth_tokens SET revoked = 1 WHERE id = ?',
        (refresh_row['access_token_id'],)
    )
    db.execute(
        'UPDATE oauth_refresh_tokens SET revoked = 1 WHERE id = ?',
        (refresh_row['id'],)
    )

    # Get scopes from the old token
    old_token = db.execute(
        'SELECT scopes FROM oauth_tokens WHERE id = ?',
        (refresh_row['access_token_id'],)
    ).fetchone()

    scopes = old_token['scopes'] if old_token else client['scopes']

    # Optionally narrow scopes
    requested_scopes = request.form.get('scope')
    if requested_scopes:
        requested_set = set(requested_scopes.split())
        original_set = set(scopes.split()) if scopes else set()
        if not requested_set.issubset(original_set):
            return jsonify({
                'error': 'invalid_scope',
                'error_description': 'Cannot expand scope beyond original grant.'
            }), 400
        scopes = requested_scopes

    # Issue new tokens
    new_access_token = generate_token()
    new_refresh_token = generate_token()
    expires_in = 3600
    expires_at = datetime.utcnow() + timedelta(seconds=expires_in)
    refresh_expires_at = datetime.utcnow() + timedelta(days=30)

    cursor = db.execute(
        '''INSERT INTO oauth_tokens (access_token_hash, token_type, client_id, scopes, expires_at)
           VALUES (?, 'Bearer', ?, ?, ?)''',
        (hash_token(new_access_token), client['client_id'], scopes, expires_at.isoformat())
    )
    new_token_id = cursor.lastrowid

    db.execute(
        '''INSERT INTO oauth_refresh_tokens (refresh_token_hash, access_token_id, client_id, expires_at)
           VALUES (?, ?, ?, ?)''',
        (hash_token(new_refresh_token), new_token_id, client['client_id'], refresh_expires_at.isoformat())
    )

    db.commit()

    log_audit_event(
        'token_refresh',
        client_id=client['client_id'],
        token_id=new_token_id,
        status='success'
    )

    return jsonify({
        'access_token': new_access_token,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'refresh_token': new_refresh_token,
        'scope': scopes
    }), 200


@app.route('/oauth/revoke', methods=['POST'])
def revoke_token():
    """OAuth 2.0 Token Revocation endpoint (RFC 7009)."""
    client, error = _authenticate_client()
    if client is None:
        return jsonify({
            'error': 'invalid_client',
            'error_description': error
        }), 401

    token = request.form.get('token')
    token_type_hint = request.form.get('token_type_hint', 'access_token')

    if not token:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'token parameter is required.'
        }), 400

    db = get_db()
    token_hash = hash_token(token)

    if token_type_hint == 'access_token':
        db.execute(
            'UPDATE oauth_tokens SET revoked = 1 WHERE access_token_hash = ? AND client_id = ?',
            (token_hash, client['client_id'])
        )
    elif token_type_hint == 'refresh_token':
        refresh_row = db.execute(
            'SELECT * FROM oauth_refresh_tokens WHERE refresh_token_hash = ? AND client_id = ?',
            (token_hash, client['client_id'])
        ).fetchone()
        if refresh_row:
            db.execute(
                'UPDATE oauth_refresh_tokens SET revoked = 1 WHERE id = ?',
                (refresh_row['id'],)
            )
            db.execute(
                'UPDATE oauth_tokens SET revoked = 1 WHERE id = ?',
                (refresh_row['access_token_id'],)
            )

    db.commit()

    log_audit_event(
        'token_revoke',
        client_id=client['client_id'],
        status='success',
        message=f'token_type_hint: {token_type_hint}'
    )

    # RFC 7009: always return 200 even if token was not found
    return '', 200


@app.route('/oauth/introspect', methods=['POST'])
def introspect_token():
    """OAuth 2.0 Token Introspection endpoint (RFC 7662)."""
    client, error = _authenticate_client()
    if client is None:
        return jsonify({
            'error': 'invalid_client',
            'error_description': error
        }), 401

    token = request.form.get('token')
    if not token:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'token parameter is required.'
        }), 400

    token_info, _, _ = validate_access_token(token)

    if token_info is None:
        return jsonify({'active': False}), 200

    return jsonify({
        'active': True,
        'scope': ' '.join(token_info.scopes),
        'client_id': token_info.client_id,
        'username': token_info.user_id,
        'token_type': token_info.token_type,
        'exp': int(token_info.expires_at.timestamp()),
        'iat': int(token_info.expires_at.timestamp()) - 3600,
        'sub': token_info.user_id or token_info.client_id,
        'iss': request.host_url.rstrip('/')
    }), 200


