@app.route('/api/v1/health', methods=['GET'])
def health_check():
    """Public health check endpoint."""
    return jsonify({
        'status': 'healthy',
        'service': 'oauth-resource-server',
        'timestamp': datetime.utcnow().isoformat()
    }), 200


@app.route('/api/v1/userinfo', methods=['GET'])
@require_oauth('profile', 'read', require_all=False)
def get_user_info():
    """Get information about the authenticated user/client."""
    token_info = g.token_info
    return jsonify({
        'client_id': token_info.client_id,
        'user_id': token_info.user_id,
        'scopes': list(token_info.scopes),
        'client_name': token_info.client_name,
        'token_expires_at': token_info.expires_at.isoformat()
    }), 200


@app.route('/api/v1/resources', methods=['GET'])
@require_oauth('read')
def list_resources():
    """Example: List resources (requires 'read' scope)."""
    return jsonify({
        'resources': [
            {'id': 1, 'name': 'Resource A', 'type': 'compute'},
            {'id': 2, 'name': 'Resource B', 'type': 'storage'},
            {'id': 3, 'name': 'Resource C', 'type': 'network'}
        ],
        'meta': {
            'total': 3,
            'client_id': g.token_info.client_id
        }
    }), 200


@app.route('/api/v1/resources', methods=['POST'])
@require_oauth('write')
def create_resource():
    """Example: Create a resource (requires 'write' scope)."""
    data = request.get_json()
    if not data or 'name' not in data:
        return jsonify({'error': 'name field is required'}), 400

    return jsonify({
        'id': uuid.uuid4().hex[:8],
        'name': data['name'],
        'type': data.get('type', 'general'),
        'created_by': g.token_info.client_id,
        'message': 'Resource created successfully'
    }), 201


@app.route('/api/v1/resources/<resource_id>', methods=['DELETE'])
@require_oauth('write', 'delete')
def delete_resource(resource_id):
    """Example: Delete a resource (requires 'write' and 'delete' scopes)."""
    return jsonify({
        'message': f'Resource {resource_id} deleted successfully',
        'deleted_by': g.token_info.client_id
    }), 200


