@app.route('/api/v1/gateway/route', methods=['POST'])
@require_oauth('gateway')
def route_request():
    """Example: Route a request through the API gateway."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required.'}), 400

    target_service = data.get('service')
    target_path = data.get('path')
    method = data.get('method', 'GET')

    if not target_service or not target_path:
        return jsonify({'error': 'service and path are required.'}), 400

    return jsonify({
        'routed': True,
        'target_service': target_service,
        'target_path': target_path,
        'method': method,
        'routed_by': g.token_info.client_id,
        'message': 'Request routed successfully (simulated)'
    }), 200


# ============================================================
# Error Handlers
# ============================================================

@app.errorhandler(404)
def not_found(e):
    return jsonify({'error': 'not_found', 'message': 'The requested resource was not found.'}), 404


@app.errorhandler(405)
def method_not_allowed(e):
    return jsonify({'error': 'method_not_allowed', 'message': 'The request method is not allowed.'}), 405


@app.errorhandler(500)
def internal_error(e):
    return jsonify({'error': 'server_error', 'message': 'An internal server error occurred.'}), 500


