def seed_initial_data():
    """Seed the database with an initial admin client for bootstrapping."""
    db = get_db()

    existing = db.execute(
        "SELECT COUNT(*) as count FROM oauth_clients"
    ).fetchone()

    if existing['count'] == 0:
        admin_client_id = 'admin-client'
        admin_client_secret = 'admin-secret-change-me'

        db.execute(
            '''INSERT INTO oauth_clients (client_id, client_secret_hash, client_name, grant_types, scopes)
               VALUES (?, ?, ?, ?, ?)''',
            (
                admin_client_id,
                hash_token(admin_client_secret),
                'Admin Bootstrap Client',
                'client_credentials',
                'admin read write delete gateway profile'
            )
        )

        # Also create a demo API client
        demo_client_id = 'demo-api-client'
        demo_client_secret = 'demo-secret-change-me'

        db.execute(
            '''INSERT INTO oauth_clients (client_id, client_secret_hash, client_name, grant_types, scopes)
               VALUES (?, ?, ?, ?, ?)''',
            (
                demo_client_id,
                hash_token(demo_client_secret),
                'Demo API Client',
                'client_credentials',
                'read write profile'
            )
        )

        db.commit()

        print("=" * 60)
        print("INITIAL SEED DATA CREATED")
        print("=" * 60)
        print(f"Admin Client ID:     {admin_client_id}")
        print(f"Admin Client Secret: {admin_client_secret}")
        print(f"Admin Scopes:        admin read write delete gateway profile")
        print("-" * 60)
        print(f"Demo Client ID:      {demo_client_id}")
        print(f"Demo Client Secret:  {demo_client_secret}")
        print(f"Demo Scopes:         read write profile")
        print("=" * 60)
        print("CHANGE THESE CREDENTIALS IN PRODUCTION!")
        print("=" * 60)


# ============================================================
# Periodic Token Cleanup
# ============================================================

@app.cli.command('cleanup-tokens')
def cleanup_expired_tokens():
    """CLI command to clean up expired tokens."""
    with app.app_context():
        db = get_db()
        now = datetime.utcnow().isoformat()

        result = db.execute(
            'DELETE FROM oauth_tokens WHERE expires_at < ? AND revoked = 1',
            (now,)
        )
        access_deleted = result.rowcount

        result = db.execute(
            'DELETE FROM oauth_refresh_tokens WHERE expires_at < ? AND revoked = 1',
            (now,)
        )
        refresh_deleted = result.rowcount

        db.commit()
        print(f"Cleaned up {access_deleted} expired access tokens and {refresh_deleted} expired refresh tokens.")


@app.cli.command('init-db')
def init_db_command():
    """CLI command to initialize the database."""
    with app.app_context():
        init_db()
        seed_initial_data()
        print("Database initialized.")


